#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int n,f[N];
struct node
{
	int x,y,z,id;
} a[N];
struct Node
{
	int u,v,w;
	bool operator<(const Node other) const
	{
		return w<other.w;
	}
};
vector<Node> g;
bool cmp1(node x,node y)
{
	return x.x<y.x;
}
bool cmp2(node x,node y)
{
	return x.y<y.y;
}
bool cmp3(node x,node y)
{
	return x.z<y.z;
}
int find(int x)
{
	if(x==f[x]) return x;
	return f[x]=find(f[x]);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		f[i]=i;
		cin>>a[i].x>>a[i].y>>a[i].z;
		a[i].id=i;
	}
	sort(a+1,a+1+n,cmp1);
	for(int i=2;i<=n;i++)
	{
		Node tmp=Node{a[i-1].id,a[i].id,a[i].x-a[i-1].x};
		g.push_back(tmp);
	}
	sort(a+1,a+1+n,cmp2);
	for(int i=2;i<=n;i++)
	{
		Node tmp=Node{a[i-1].id,a[i].id,a[i].y-a[i-1].y};
		g.push_back(tmp);
	}
	sort(a+1,a+1+n,cmp3);
	for(int i=2;i<=n;i++)
	{
		Node tmp=Node{a[i-1].id,a[i].id,a[i].z-a[i-1].z};
		g.push_back(tmp);
	}
	sort(g.begin(),g.end());
	ll ans=0;
	for(int i=0;i<g.size();i++)
	{
		Node tmp=g[i];
		int fu=find(tmp.u),fv=find(tmp.v);
		if(fu!=fv)
		{
			f[fu]=fv;
			ans+=tmp.w;
		}
	}
	cout<<ans;
	return 0;
}
